'use client';

import Image from 'next/image';

export default function PromoBanner({ currentSlide = 1 }) {
  return (
    <div>
      <div className="promo-banner">
        <div className="promo-content">
          <div className="promo-title">Big Sale</div>
          <div className="promo-subtitle">Up to 50% Discount</div>
        </div>
        <div className="promo-image-wrapper">
          <Image
            src="/images/promo-woman.png"
            alt="Promotional"
            width={120}
            height={120}
            className="promo-image"
          />
        </div>
      </div>
      <div className="promo-dots">
        {[1, 2, 3, 4, 5].map((dot) => (
          <div
            key={dot}
            className={`promo-dot ${dot === currentSlide ? 'active' : ''}`}
          />
        ))}
      </div>
    </div>
  );
}

