'use client';

import { FiHome, FiShoppingCart, FiStar, FiUser } from 'react-icons/fi';
import { HiLightningBolt } from 'react-icons/hi';
import { usePathname } from 'next/navigation';
import Link from 'next/link';

export default function BottomNav() {
  const pathname = usePathname();
  const isCartPage = pathname === '/cart';

  const navItems = [
    { icon: FiHome, label: 'Home', path: '/' },
    { icon: HiLightningBolt, label: 'Flash', path: '/flash' },
    { icon: FiShoppingCart, label: 'Cart', path: '/cart' },
    { icon: FiStar, label: 'Favorites', path: '/favorites' },
    { icon: FiUser, label: 'Profile', path: '/profile' },
  ];

  return (
    <nav className="bottom-nav">
      {navItems.map((item) => {
        const Icon = item.icon;
        const isActive = item.path === pathname;
        const isCartActive = item.path === '/cart' && isCartPage;

        return (
          <Link key={item.path} href={item.path} className="nav-item">
            <div className={`nav-icon-wrapper ${isActive || isCartActive ? 'active' : ''}`}>
              <Icon className="nav-icon" />
            </div>
            <span style={{ fontSize: '10px', marginTop: '2px' }}>{item.label}</span>
          </Link>
        );
      })}
    </nav>
  );
}

